import{_ as e,o as n,c as t,a2 as s}from"./chunks/framework.Wufm-cgV.js";const g=JSON.parse('{"title":"Tokens & Teams","description":"Managing API keys and team access","frontmatter":{"title":"Tokens & Teams","description":"Managing API keys and team access"},"headers":[],"relativePath":"guide/tokens-teams.md","filePath":"guide/tokens-teams.md"}'),o={name:"guide/tokens-teams.md"};function i(r,a,l,c,m,p){return n(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="tokens-teams" tabindex="-1">Tokens &amp; Teams <a class="header-anchor" href="#tokens-teams" aria-label="Permalink to &quot;Tokens &amp; Teams&quot;">​</a></h1><h2 id="api-tokens" tabindex="-1">API Tokens <a class="header-anchor" href="#api-tokens" aria-label="Permalink to &quot;API Tokens&quot;">​</a></h2><p>Tokens are the API keys clients use to authenticate with wr-proxy. Each token can have:</p><ul><li><strong>Model whitelist</strong> — restrict which models this token can use</li><li><strong>Quota</strong> — total token limit</li><li><strong>Rate limit</strong> — requests per minute</li><li><strong>Smart downgrade</strong> — automatically use a cheaper model on errors</li><li><strong>Desensitization</strong> — enable/disable PII stripping</li></ul><h3 id="creating-a-token" tabindex="-1">Creating a Token <a class="header-anchor" href="#creating-a-token" aria-label="Permalink to &quot;Creating a Token&quot;">​</a></h3><ol><li>Go to <strong>Tokens</strong> → <strong>+ Create</strong></li><li>Enter a name and associate it with an organization</li><li>Set model access (whitelist or allow all)</li><li>Configure quota and rate limits</li><li>Enable smart downgrade if desired</li></ol><h2 id="organizations" tabindex="-1">Organizations <a class="header-anchor" href="#organizations" aria-label="Permalink to &quot;Organizations&quot;">​</a></h2><p>Organizations represent your company structure. They can be nested:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Engineering (company)</span></span>
<span class="line"><span>├── Backend (department)</span></span>
<span class="line"><span>└── Frontend (department)</span></span>
<span class="line"><span>ML Research (company)</span></span>
<span class="line"><span>└── LLM Ops (department)</span></span>
<span class="line"><span>Product (company)</span></span></code></pre></div><p>Each token belongs to an organization, enabling per-organization quota tracking and billing reports.</p><h2 id="quota-management" tabindex="-1">Quota Management <a class="header-anchor" href="#quota-management" aria-label="Permalink to &quot;Quota Management&quot;">​</a></h2><p>Quotas can be set per token:</p><ul><li><strong>Total quota</strong> — maximum tokens the token can consume</li><li><strong>Used quota</strong> — consumed tokens (auto-tracked)</li><li><strong>Remaining</strong> — auto-calculated</li></ul><p>When a token&#39;s quota is nearly exhausted, alerts can be triggered.</p><h2 id="team-members" tabindex="-1">Team Members <a class="header-anchor" href="#team-members" aria-label="Permalink to &quot;Team Members&quot;">​</a></h2><p>Each token has a member email for identification. Members can be assigned to organizations, and the admin can view per-member usage statistics from the billing dashboard.</p>`,16)])])}const h=e(o,[["render",i]]);export{g as __pageData,h as default};
